// --- Banners ---

export const getBanners = async (params) => {
    const response = await api.get('/masters/banners', { params });
    return getData(response);
};

export const getBannerById = async (id) => {
    const response = await api.get(`/masters/banners/${id}`);
    return getData(response);
};

export const createBanner = async (data) => {
    const formData = new FormData();
    if (data.banner_image) formData.append('banner_image', data.banner_image);
    if (data.banner_image_mr) formData.append('banner_image_mr', data.banner_image_mr);
    if (data.display_order !== undefined) formData.append('display_order', data.display_order);
    if (data.is_active !== undefined) formData.append('is_active', data.is_active);
    const response = await api.post('/masters/banners', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
    });
    return getData(response);
};

export const updateBanner = async (id, data) => {
    const formData = new FormData();
    if (data.banner_image) formData.append('banner_image', data.banner_image);
    if (data.banner_image_mr) formData.append('banner_image_mr', data.banner_image_mr);
    if (data.display_order !== undefined) formData.append('display_order', data.display_order);
    if (data.is_active !== undefined) formData.append('is_active', data.is_active);
    const response = await api.put(`/masters/banners/${id}`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
    });
    return getData(response);
};

export const deleteBanner = async (id) => {
    await api.delete(`/masters/banners/${id}`);
};
